ambiguous_dsl.choice_dsl:
PREFIX : <http://ambrosia.example.org/entertainment#>
PREFIX p: <http://ambrosia.example.org/entertainment/prop#>
PREFIX xsd: <http://www.w3.org/2001/XMLSchema#>
CHOICE vague {
  component: { SELECT ?title ?number_of_episodes WHERE {
  ?show a :Show .
  ?show p:title ?title .
  ?show p:Number_of_episodes ?number_of_episodes .
  ?show p:Number_of_episodes ?number_of_episodes_o .
}
ORDER BY DESC(?number_of_episodes_o)
LIMIT 3 }
  full: { SELECT ?title ?number_of_seasons ?number_of_episodes WHERE {
  ?show a :Show .
  ?show p:title ?title .
  ?show p:Number_of_seasons ?number_of_seasons .
  ?show p:Number_of_episodes ?number_of_episodes .
  ?show p:Number_of_seasons ?number_of_seasons_o .
  ?show p:Number_of_episodes ?number_of_episodes_o .
}
ORDER BY ASC(?number_of_seasons_o) DESC(?number_of_episodes_o)
LIMIT 3 }
  component_2: { SELECT ?title ?number_of_seasons WHERE {
  ?show a :Show .
  ?show p:title ?title .
  ?show p:Number_of_seasons ?number_of_seasons .
  ?show p:Number_of_seasons ?number_of_seasons_o .
}
ORDER BY DESC(?number_of_seasons_o)
LIMIT 3 }
}

PREFIX : <http://ambrosia.example.org/entertainment#>
PREFIX p: <http://ambrosia.example.org/entertainment/prop#>
PREFIX xsd: <http://www.w3.org/2001/XMLSchema#>
CHOICE vague {
  component: { SELECT ?title ?number_of_seasons ?release_year WHERE {
  ?show a :Show .
  ?show p:title ?title .
  ?show p:Number_of_seasons ?number_of_seasons .
  ?show p:release_year ?release_year .
  ?show p:genre ?genre_f .
  FILTER(STR(?genre_f) = "Comedy")
} }
  full: { SELECT ?title ?number_of_seasons ?number_of_episodes ?release_year WHERE {
  ?show a :Show .
  ?show p:title ?title .
  ?show p:Number_of_seasons ?number_of_seasons .
  ?show p:Number_of_episodes ?number_of_episodes .
  ?show p:release_year ?release_year .
  ?show p:genre ?genre_f .
  FILTER(STR(?genre_f) = "Comedy")
} }
  component_2: { SELECT ?title ?number_of_episodes ?release_year WHERE {
  ?show a :Show .
  ?show p:title ?title .
  ?show p:Number_of_episodes ?number_of_episodes .
  ?show p:release_year ?release_year .
  ?show p:genre ?genre_f .
  FILTER(STR(?genre_f) = "Comedy")
} }
}
